class Solution {
    public int countOperations(int num1, int num2) {
        int a = num1;
        int b = num2;
        int count = 0;
        while (a != 0 && b != 0) {
            if (a > b) {
                count += a / b;
                a %= b;
            } else {
                count += b / a;
                b %= a;
            }
        }
        return count;
    }
}

